@app.route("/users", methods=["POST"])
def create_user():
    data = request.get_json(force=True, silent=True) or {}
    email = (data.get("email") or "").strip().lower()
    username = (data.get("username") or "").strip()
    display_name = (data.get("display_name") or "").strip() or username or email
    bio = data.get("bio") or ""
    roles = data.get("roles") or ["user"]
    if not isinstance(roles, list):
        roles = ["user"]

    if not email:
        return jsonify({"error": "email_required"}), 400

    doc = {
        "email": email,
        "username": username if username else None,
        "display_name": display_name,
        "bio": bio,
        "roles": roles,
        "created_at": now_utc(),
        "updated_at": now_utc(),
        "meta": data.get("meta") if isinstance(data.get("meta"), dict) else {},
    }

    try:
        res = users.insert_one(doc)
    except DuplicateKeyError:
        return jsonify({"error": "duplicate_user"}), 409

    created = users.find_one({"_id": res.inserted_id})
    return jsonify(serialize_doc(created)), 201

