@app.route("/documents", methods=["GET"])
def query_documents():
    text = (request.args.get("text") or "").strip()
    q = (request.args.get("q") or "").strip()
    status = (request.args.get("status") or "").strip().lower()
    tag = (request.args.get("tag") or "").strip()
    author_id = to_oid(request.args.get("author_id"))
    slug = (request.args.get("slug") or "").strip()
    include_author = parse_bool(request.args.get("include_author"), False)

    limit = parse_int(request.args.get("limit"), 20, 1, 200)
    skip = parse_int(request.args.get("skip"), 0, 0, 100_000)
    sort = (request.args.get("sort") or "-updated_at").strip()
    sort_field = sort.lstrip("-")
    sort_dir = DESCENDING if sort.startswith("-") else ASCENDING

    filt = {}
    if status:
        filt["status"] = status
    if tag:
        filt["tags"] = tag
    if author_id:
        filt["author_id"] = author_id
    if slug:
        filt["slug"] = slug
    if q:
        regex = {"$regex": q, "$options": "i"}
        filt["$or"] = [{"title": regex}, {"body": regex}, {"slug": regex}, {"tags": regex}]
    if text:
        filt["$text"] = {"$search": text}

    if not include_author:
        cur = documents.find(filt).sort(sort_field, sort_dir).skip(skip).limit(limit)
        return jsonify([serialize_doc(d) for d in cur])

    pipeline = []
    pipeline.append({"$match": filt})
    pipeline.append({"$sort": {sort_field: 1 if sort_dir == ASCENDING else -1}})
    if skip:
        pipeline.append({"$skip": skip})
    pipeline.append({"$limit": limit})
    pipeline.append({"$lookup": {"from": "users", "localField": "author_id", "foreignField": "_id", "as": "author"}})
    pipeline.append({"$unwind": {"path": "$author", "preserveNullAndEmptyArrays": True}})
    pipeline.append({"$project": {
        "_id": 1, "title": 1, "body": 1, "slug": 1, "status": 1, "tags": 1,
        "author_id": 1, "created_at": 1, "updated_at": 1, "meta": 1,
        "author._id": 1, "author.email": 1, "author.username": 1, "author.display_name": 1, "author.roles": 1
    }})

    out = list(documents.aggregate(pipeline))
    return jsonify([serialize_doc(d) for d in out])

