@app.route("/analytics/documents/by_author", methods=["GET"])
def analytics_documents_by_author():
    limit = parse_int(request.args.get("limit"), 50, 1, 200)
    status = (request.args.get("status") or "").strip().lower()

    match = {}
    if status:
        match["status"] = status

    pipeline = [
        {"$match": match},
        {"$group": {"_id": "$author_id", "count": {"$sum": 1}, "latest": {"$max": "$updated_at"}}},
        {"$lookup": {"from": "users", "localField": "_id", "foreignField": "_id", "as": "author"}},
        {"$unwind": {"path": "$author", "preserveNullAndEmptyArrays": True}},
        {"$project": {
            "_id": 0,
            "author_id": {"$cond": [{"$ifNull": ["$_id", False]}, {"$toString": "$_id"}, None]},
            "count": 1,
            "latest": 1,
            "author": {
                "_id": {"$cond": [{"$ifNull": ["$author._id", False]}, {"$toString": "$author._id"}, None]},
                "email": "$author.email",
                "username": "$author.username",
                "display_name": "$author.display_name",
            },
        }},
        {"$sort": {"count": -1, "latest": -1}},
        {"$limit": limit},
    ]
    out = list(documents.aggregate(pipeline))
    for r in out:
        if isinstance(r.get("latest"), datetime):
            r["latest"] = r["latest"].isoformat()
    return jsonify(out)

@app.route("/analytics/documents/timeline", methods=["GET"])
def analytics_documents_timeline():
    status = (request.args.get("status") or "").strip().lower()
    tz = request.args.get("tz")
    interval = (request.args.get("interval") or "day").strip().lower()
    limit = parse_int(request.args.get("limit"), 60, 1, 365)

    if interval not in ("day", "month"):
        return jsonify({"error": "invalid_interval"}), 400

    match = {}
    if status:
        match["status"] = status

    date_expr = "$created_at"
    if interval == "day":
        fmt = "%Y-%m-%d"
    else:
        fmt = "%Y-%m"

    group_id = {"$dateToString": {"format": fmt, "date": date_expr}}
    if tz:
        group_id["$dateToString"]["timezone"] = tz

    pipeline = [
        {"$match": match},
        {"$group": {"_id": group_id, "count": {"$sum": 1}}},
        {"$project": {"_id": 0, "bucket": "$_id", "count": 1}},
        {"$sort": {"bucket": -1}},
        {"$limit": limit},
        {"$sort": {"bucket": 1}},
    ]
    out = list(documents.aggregate(pipeline))
    return jsonify(out)

