@app.route("/aggregate/documents", methods=["POST"])
def custom_aggregate_documents():
    payload = request.get_json(force=True, silent=True) or {}
    pipeline = payload.get("pipeline")

    if not isinstance(pipeline, list):
        return jsonify({"error": "pipeline_must_be_list"}), 400

    max_stages = parse_int(os.environ.get("MAX_AGG_STAGES"), 25, 1, 200)
    if len(pipeline) > max_stages:
        return jsonify({"error": "too_many_stages", "max_stages": max_stages}), 400

    allow_disk_use = parse_bool(payload.get("allowDiskUse"), False)
    try:
        out = list(documents.aggregate(pipeline, allowDiskUse=allow_disk_use))
    except Exception as e:
        return jsonify({"error": "aggregation_error", "detail": str(e)}), 400

    return jsonify([serialize_doc(x) for x in out])

